def _get_gate(self, c: int):
    key = str(c)
    if key not in self._gates:
        self._gates[key] = nn.Sequential(nn.Conv1d(c, c, 1), nn.Sigmoid())
    return self._gates[key]

def forward(self, feats):
    if isinstance(feats, (list, tuple)):
        outputs = []
        for feat in feats:
            b, c, h, w = feat.shape
            gate = self._get_gate(c)
            pooled = feat.view(b, c, -1)
            weights = gate(pooled)
            outputs.append(feat * weights.view(b, c, h, w))
        return outputs
